// src/App.js
import React, { useState, useEffect } from "react";
import Dice from "react-dice-roll";

// --- Board Image path ---
const boardImage = "/torahpoly_board.png";

// --- Red Properties ---
const schemRoyalEstates = {
  type: "property",
  name: "Schem Royal Estates",
  colorGroup: "red",
  price: 300,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 },
  buildCost: { house: 200, hotel: 300 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const schemYosephGardens = {
  type: "property",
  name: "Schem Yoseph Gardens",
  colorGroup: "red",
  price: 300,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 },
  buildCost: { house: 200, hotel: 300 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const schemDreamResorts = {
  type: "property",
  name: "Schem Dream Resorts",
  colorGroup: "red",
  price: 300,
  rent: { base: 50, house1: 100, house2: 650, house3: 750, hotel: 750 },
  buildCost: { house: 150, hotel: 250 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Yellow ---
const ephraimHilltops = {
  type: "property",
  name: "Ephraim Hilltops",
  colorGroup: "yellow",
  price: 300,
  rent: { base: 50, house1: 300, house2: 400, house3: 500, hotel: 800 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Green ---
const gushKatif = {
  type: "property",
  name: "Gush Katif",
  colorGroup: "green",
  price: 350,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 1000 },
  buildCost: { house: 150, hotel: 250 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const neveDekalim = {
  type: "property",
  name: "Neve Dekalim",
  colorGroup: "green",
  price: 350,
  rent: { base: 50, house1: 200, house2: 300, house3: 650, hotel: 800 },
  buildCost: { house: 150, hotel: 200 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const ganOr = {
  type: "property",
  name: "Gan Or",
  colorGroup: "green",
  price: 350,
  rent: { base: 50, house1: 100, house2: 300, house3: 650, hotel: 800 },
  buildCost: { house: 150, hotel: 200 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Purple ---
const jerusalemHills = {
  type: "property",
  name: "Jerusalem Hills",
  colorGroup: "purple",
  price: 150,
  rent: { base: 10, house1: 200, house2: 250, house3: 300, hotel: 400 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const jerusalemHillsOrchard = {
  type: "property",
  name: "Jerusalem Hills Orchard",
  colorGroup: "purple",
  price: 150,
  rent: { base: 10, house1: 200, house2: 250, house3: 300, hotel: 400 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Gold ---
const hevronElonMamrei = {
  type: "property",
  name: "Hevron Elon Mamrei",
  colorGroup: "gold",
  price: 240,
  rent: { base: 30, house1: 70, house2: 200, house3: 550, hotel: 650 },
  buildCost: { house: 80, hotel: 150 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const hevronLuxuryCondos = {
  type: "property",
  name: "Hevron Luxury Condos",
  colorGroup: "gold",
  price: 180,
  rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 },
  buildCost: { house: 60, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const hevronHiTech = {
  type: "property",
  name: "Hevron Hi Tech",
  colorGroup: "gold",
  price: 180,
  rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 },
  buildCost: { house: 60, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Board Events ---
const boardEvents = {
  1: { type: "property", card: schemYosephGardens },
  3: { type: "property", card: schemRoyalEstates },
  4: { type: "property", card: schemDreamResorts },
  7: { type: "property", card: ephraimHilltops },
  11: { type: "property", card: gushKatif },
  12: { type: "property", card: neveDekalim },
  14: { type: "property", card: ganOr },
  28: { type: "property", card: jerusalemHillsOrchard },
  29: { type: "property", card: jerusalemHills },
  35: { type: "property", card: hevronElonMamrei },
  37: { type: "property", card: hevronLuxuryCondos },
  38: { type: "property", card: hevronHiTech },
};

// --- Board Layout ---
function buildBoardPositions(refSize = 1200, margin = 100, spacesPerSide = 11) {
  const positions = [];
  const step = (refSize - 2 * margin) / (spacesPerSide - 1);

  const topY = margin;
  for (let i = 0; i < spacesPerSide; i++) positions.push({ x: margin + i * step, y: topY });
  const rightX = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: rightX, y: topY + i * step });
  const bottomY = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: rightX - i * step, y: bottomY });
  const leftX = margin;
  for (let i = 1; i < spacesPerSide - 1; i++) positions.push({ x: leftX, y: bottomY - i * step });

  return positions.slice(0, 44);
}

const referenceSize = 1200;
const defaultBoardPositions = buildBoardPositions();

// --- Player Panel Modal (ONLY CHANGE IS HERE) ---
function PlayerPanelModal({ player, onClose }) {
  if (!player) return null;

  const ownedProperties = Object.values(boardEvents)
    .map(e => e.card)
    .filter(card => card.ownerIndex === player.index);

  const calculateCurrentRent = (card) => {
    if (card.hotel) return card.rent.hotel;
    if (card.houses === 3) return card.rent.house3;
    if (card.houses === 2) return card.rent.house2;
    if (card.houses === 1) return card.rent.house1;
    return card.rent.base;
  };

  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>{player.name}'s Properties</h2>

        {ownedProperties.length === 0 ? (
          <p>No properties owned.</p>
        ) : (
          <ul style={{ textAlign: "left" }}>
            {ownedProperties.map((prop, idx) => (
              <li key={idx} style={{ marginBottom: 12 }}>
                <div
                  style={{
                    height: 10,
                    backgroundColor: prop.colorGroup,
                    borderRadius: 4,
                    marginBottom: 6,
                  }}
                />
                <strong>{prop.name}</strong><br />
                Price: ${prop.price}<br />
                Houses: {prop.houses}, Hotel: {prop.hotel ? "Yes" : "No"}<br />
                Current Rent: ${calculateCurrentRent(prop)}
              </li>
            ))}
          </ul>
        )}

        <button style={modalStyles.button} onClick={onClose}>Close</button>
      </div>
    </div>
  );
}

// --- Main App ---
function App() {
  const [players, setPlayers] = useState([]);
  const [newPlayerName, setNewPlayerName] = useState("");
  const [newPlayerColor, setNewPlayerColor] = useState("");
  const [gameStarted, setGameStarted] = useState(false);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [boardWidth, setBoardWidth] = useState(Math.min(window.innerWidth * 0.95, referenceSize));
  const [boardPositions] = useState(defaultBoardPositions);
  const [diceRolls, setDiceRolls] = useState([]);
  const [showPanel, setShowPanel] = useState(null);

  const availableColors = ["black", "purple", "blue", "brown", "orange", "red", "green"];

  useEffect(() => {
    const handleResize = () => setBoardWidth(Math.min(window.innerWidth * 0.95, referenceSize));
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const addPlayer = () => {
    if (!newPlayerName || !newPlayerColor) return;
    setPlayers([...players, {
      name: newPlayerName,
      color: newPlayerColor,
      position: 0,
      money: 2000,
      index: players.length,
    }]);
    setNewPlayerName("");
    setNewPlayerColor("");
  };

  const rollDice = (val) => {
    setDiceRolls(prev => {
      const next = [...prev, val];
      if (next.length === 2) {
        const steps = next[0] + next[1];
        const updated = [...players];
        updated[currentPlayerIndex].position =
          (updated[currentPlayerIndex].position + steps) % boardPositions.length;
        setPlayers(updated);
        return [];
      }
      return next;
    });
  };

  return (
    <div style={styles.container}>
      <h1>TorahPoly Monopoly Game</h1>

      {!gameStarted ? (
        <>
          <div style={styles.inputRow}>
            <input value={newPlayerName} onChange={e => setNewPlayerName(e.target.value)} placeholder="Name" />
            <select value={newPlayerColor} onChange={e => setNewPlayerColor(e.target.value)}>
              <option value="">Color</option>
              {availableColors.map(c => <option key={c}>{c}</option>)}
            </select>
            <button onClick={addPlayer}>Add Player</button>
          </div>

          <ul>
            {players.map((p, i) => (
              <li key={i} style={{ color: p.color }}>
                {p.name}
                <button onClick={() => setShowPanel(i)}>View Properties</button>
              </li>
            ))}
          </ul>

          <button onClick={() => setGameStarted(true)}>Start Game</button>
        </>
      ) : (
        <>
          <img src={boardImage} alt="Board" style={{ width: boardWidth }} />

          <div style={{ display: "flex", justifyContent: "center", gap: 20 }}>
            <Dice onRoll={rollDice} />
            <Dice onRoll={rollDice} />
          </div>
        </>
      )}

      {showPanel !== null && (
        <PlayerPanelModal player={players[showPanel]} onClose={() => setShowPanel(null)} />
      )}
    </div>
  );
}

